using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class ChallengeParticipantConfiguration : IEntityTypeConfiguration<ChallengeParticipant>{public void Configure(EntityTypeBuilder<ChallengeParticipant> builder){builder.ToTable("challenge_participants");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("participant_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.StartingValue).HasColumnType("decimal(8,2)");builder.Property(e => e.CurrentValue).HasColumnType("decimal(8,2)");builder.Property(e => e.FinalScore).HasColumnType("decimal(8,2)");builder.HasOne(e => e.Challenge).WithMany(c => c.Participants).HasForeignKey(e => e.ChallengeId).OnDelete(DeleteBehavior.Cascade);builder.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.Cascade);builder.HasOne(e => e.SubGroup).WithMany().HasForeignKey(e => e.SubGroupId);builder.HasIndex(e => new { e.ChallengeId, e.UserId }).IsUnique();}}
